@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <nav class="settings-sidebar">
        <h3 class="settings-sidebar-title">Settings</h3>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="settings-nav-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </li>
            }
        </ul>
    </nav>

    <section class="settings-content">
        @switch (ActiveSection)
        {
            case "profile":
                <SettingsProfileSection />
                break;
            case "notifications":
                <SettingsNotificationsSection />
                break;
            case "security":
                <SettingsSecuritySection />
                break;
            case "appearance":
                <SettingsAppearanceSection />
                break;
        }
    </section>
</div>

@code {
    private string ActiveSection { get; set; } = "profile";

    private readonly record struct NavItem(string Key, string Label, string Icon);

    private static readonly NavItem[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];
}

.settings-layout {
    display: flex;
    min-height: 80vh;
    gap: 0;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
}

.settings-sidebar {
    width: 240px;
    min-width: 240px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.settings-sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-size: 1.1rem;
    font-weight: 600;
    color: #333;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    cursor: pointer;
    color: #555;
    font-size: 0.95rem;
    transition: background 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.settings-nav-item:hover {
    background: #e9ecef;
    color: #333;
}

.settings-nav-item.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.settings-nav-icon {
    font-size: 1.15rem;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

