@using sv_8b0cc8892d6a463297a17ed3d889b966.Models
@inject ISettingsService SettingsService

<div class="section-panel">
    <h4 class="section-title">Profile</h4>

    @if (_loading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="toast-message @(_isError ? "toast-error" : "toast-success")">
                @_message
            </div>
        }

        <div class="profile-form">
            <div class="avatar-area">
                <div class="avatar-preview">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" />
                    }
                    else
                    {
                        <span class="avatar-placeholder">👤</span>
                    }
                </div>
                <div class="avatar-url-display">
                    <label>Avatar URL</label>
                    <span class="text-muted small">@(_avatarUrl ?? "Not set")</span>
                </div>
            </div>

            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" class="form-control" @bind="_displayName" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" class="form-control" @bind="_email" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save Changes")
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
                    Discard Changes
                </button>
            </div>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _isError;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _savedProfile = profile;
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            _message = "Profile saved successfully!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _message = $"Error saving profile: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _message = null;
    }
}

.section-panel {
    max-width: 640px;
}

.section-title {
    margin-bottom: 1.5rem;
    font-weight: 600;
    color: #333;
}

.toast-message {
    padding: 0.75rem 1rem;
    border-radius: 6px;
    margin-bottom: 1rem;
    font-size: 0.9rem;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

.profile-form {
    display: flex;
    flex-direction: column;
    gap: 1.25rem;
}

.avatar-area {
    display: flex;
    align-items: center;
    gap: 1.25rem;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    overflow: hidden;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px solid #dee2e6;
    flex-shrink: 0;
}

.avatar-preview img {
    width: 100%;
