    align-items: center;
    padding: 0.85rem 1rem;
    cursor: pointer;
    margin: 0;
    border-bottom: 1px solid #dee2e6;
}

.toggle-row:last-child {
    border-bottom: none;
}

.toggle-row:hover {
    background: #f8f9fa;
}

.channels-section h5 {
    font-size: 1rem;
    font-weight: 600;
