.section-panel {
    max-width: 640px;
}

.section-title {
    margin-bottom: 1.5rem;
    font-weight: 600;
    color: #333;
}

.toast-message {
    padding: 0.75rem 1rem;
    border-radius: 6px;
    margin-bottom: 1rem;
    font-size: 0.9rem;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

.profile-form {
    display: flex;
    flex-direction: column;
    gap: 1.25rem;
}

.avatar-area {
    display: flex;
    align-items: center;
    gap: 1.25rem;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    overflow: hidden;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px solid #dee2e6;
    flex-shrink: 0;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2rem;
}

.avatar-url-display {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.avatar-url-display label {
    font-weight: 600;
    font-size: 0.85rem;
    color: #555;
}

.form-group {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
}

.form-group label {
    font-weight: 600;
    font-size: 0.9rem;
    color: #444;
}

.button-group {
    display: flex;
    gap: 0.75rem;
    margin-top: 0.5rem;
}

