.section-panel {
    max-width: 640px;
}

.section-title {
    margin-bottom: 1.5rem;
    font-weight: 600;
    color: #333;
}

.toast-message {
    padding: 0.75rem 1rem;
    border-radius: 6px;
    margin-bottom: 1rem;
    font-size: 0.9rem;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.notifications-form {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    overflow: hidden;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.85rem 1rem;
    cursor: pointer;
    margin: 0;
    border-bottom: 1px solid #dee2e6;
}

.toggle-row:last-child {
    border-bottom: none;
}

.toggle-row:hover {
    background: #f8f9fa;
}

.channels-section h5 {
    font-size: 1rem;
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.channels-list {
    display: flex;
    flex-direction: column;
    gap: 0;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    overflow: hidden;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.65rem 1rem;
    cursor: pointer;
    margin: 0;
    border-bottom: 1px solid #eee;
}

.channel-item:last-child {
    border-bottom: none;
}

.channel-item:hover {
    background: #f8f9fa;
}

.button-group {
    display: flex;
    gap: 0.75rem;
    margin-top: 0.5rem;
}

