toolArgs.file_text:
@using sv_8b0cc8892d6a463297a17ed3d889b966.Models
@inject ISettingsService SettingsService

<div class="section-panel">
    <h4 class="section-title">Security</h4>

    @if (_loading)
    {
        <p class="text-muted">Loading security settings…</p>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="toast-message @(_isError ? "toast-error" : "toast-success")">
                @_message
            </div>
        }

        <!-- Change Password Panel -->
        <div class="expandable-panel">
            <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span>Change Password</span>
                <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
            </button>
            @if (_passwordPanelOpen)
            {
                <div class="panel-body">
                    <div class="form-group">
                        <label for="currentPassword">Current Password</label>
                        <input id="currentPassword" type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="form-group">
                        <label for="newPassword">New Password</label>
                        <input id="newPassword" type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="form-group">
                        <label for="confirmPassword">Confirm Password</label>
                        <input id="confirmPassword" type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @(_changingPassword ? "Updating…" : "Update Password")
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="tfa-section">
            <div class="tfa-row">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="tfa-status">
                        <span class="status-indicator @(_twoFactorEnabled ? "status-on" : "status-off")"></span>
                        <span class="text-muted small">@(_twoFactorEnabled ? "Enabled" : "Disabled")</span>
                    </div>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span>@(_twoFactorEnabled ? "On" : "Off")</span>
                </label>
            </div>
            @if (_settings?.LastPasswordChange is not null)
            {
                <p class="text-muted small mt-1">Last password change: @_settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
            }
        </div>

        <!-- Active Sessions -->
        <div class="sessions-section">
            <h5>Active Sessions</h5>
            @if (_sessions.Count == 0)
            {
                <p class="text-muted">No active sessions.</p>
            }
            else
            {
                <table class="table sessions-table">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td>
                                    @if (session != _sessions.FirstOrDefault())
                                    {
                                        @if (_confirmRevokeId == session.Id)
                                        {
                                            <span class="revoke-confirm">
                                                <span>Revoke?</span>
                                                <button class="btn btn-sm btn-danger" @onclick="() => RevokeSessionAsync(session.Id)">
                                                    Yes
                                                </button>
                                                <button class="btn btn-sm btn-outline-secondary" @onclick="() => _confirmRevokeId = null">
                                                    No
                                                </button>
                                            </span>
                                        }
                                        else
                                        {
                                            <button class="btn btn-sm btn-outline-danger" @onclick="() => _confirmRevokeId = session.Id">
                                                Revoke
                                            </button>
                                        }
                                    }
                                    else
                                    {
                                        <span class="badge bg-success">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private string? _message;
    private bool _isError;

    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;

    private bool _twoFactorEnabled;
    private SecuritySettings? _settings;
    private List<ActiveSession> _sessions = new();
    private string? _confirmRevokeId;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _settings.TwoFactorEnabled;
        _sessions = _settings.Sessions.ToList();
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "New password cannot be empty.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _message = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordPanelOpen = false;
        }
        catch (Exception ex)
        {
            _message = $"Error: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        try
        {
            await SettingsService.RevokeSessionAsync(sessionId);
            _sessions.RemoveAll(s => s.Id == sessionId);
            _confirmRevokeId = null;
            _message = "Session revoked.";
            _isError = false;
        }
        catch (Exception ex)
        {
            _message = $"Error revoking session: {ex.Message}";
            _isError = true;
        }
    }
}

