.section-panel {
    max-width: 720px;
}

.section-title {
    margin-bottom: 1.5rem;
    font-weight: 600;
    color: #333;
}

.toast-message {
    padding: 0.75rem 1rem;
    border-radius: 6px;
    margin-bottom: 1rem;
    font-size: 0.9rem;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

/* Expandable Panel */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    margin-bottom: 1.5rem;
    overflow: hidden;
}

.panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.85rem 1rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    font-weight: 600;
    font-size: 0.95rem;
    color: #333;
}

.panel-header:hover {
    background: #e9ecef;
}

.expand-icon {
    font-size: 0.75rem;
    color: #888;
}

.panel-body {
    padding: 1.25rem 1rem;
    display: flex;
    flex-direction: column;
    gap: 1rem;
    border-top: 1px solid #dee2e6;
}

.form-group {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
}

.form-group label {
    font-weight: 600;
    font-size: 0.9rem;
    color: #444;
}

/* 2FA */
.tfa-section {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 1rem;
    margin-bottom: 1.5rem;
}

.tfa-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.tfa-status {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-top: 0.25rem;
}

.status-indicator {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    display: inline-block;
}

.status-on {
    background: #198754;
}

.status-off {
    background: #dc3545;
}

.toggle-switch {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
}

/* Sessions */
.sessions-section {
    margin-bottom: 1rem;
}

.sessions-section h5 {
    font-size: 1rem;
    font-weight: 600;
    margin-bottom: 0.75rem;
}

.sessions-table {
    font-size: 0.9rem;
}

.revoke-confirm {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    font-size: 0.85rem;
}

