toolArgs.file_text:
@using sv_8b0cc8892d6a463297a17ed3d889b966.Models
@inject ISettingsService SettingsService

<div class="section-panel">
    <h4 class="section-title">Appearance</h4>

    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="toast-message toast-success">@_message</div>
        }

        <div class="appearance-form">
            <!-- Theme -->
            <fieldset class="option-group">
                <legend>Theme</legend>
                <div class="radio-options">
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <label class="radio-option @(_theme == theme ? "selected" : "")">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </fieldset>

            <!-- Font Size -->
            <fieldset class="option-group">
                <legend>Font Size</legend>
                <div class="radio-options">
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <label class="radio-option @(_fontSize == size ? "selected" : "")">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </fieldset>

            <!-- Language -->
            <div class="form-group">
                <label for="language">Language</label>
                <select id="language" class="form-select" @bind="_language">
                    <option value="en">English</option>
                    <option value="es">Español</option>
                    <option value="fr">Français</option>
                    <option value="de">Deutsch</option>
                    <option value="ja">日本語</option>
                    <option value="zh">中文</option>
                </select>
            </div>

            <!-- Compact Mode -->
            <label class="toggle-row">
                <span>Compact Mode</span>
                <input type="checkbox" class="form-check-input" @bind="_compactMode" />
            </label>

            <!-- Live Preview -->
            <div class="preview-area @GetPreviewClasses()">
                <h6 class="preview-title">Live Preview</h6>
                <p class="preview-text">
                    This is a preview of your selected appearance settings. The theme, font size,
                    and compact mode are reflected here.
                </p>
                <div class="preview-card">
                    <strong>Sample Card</strong>
                    <p>Dashboard content would appear like this.</p>
                    <button class="preview-btn">Action Button</button>
                </div>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>
            </div>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _message;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var theme = _theme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        };
        var size = _fontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-small",
            "large" => "preview-font-large",
            _ => "preview-font-medium"
        };
        var compact = _compactMode ? "preview-compact" : "";
        return $"{theme} {size} {compact}";
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _message = "Appearance settings saved!";
        _saving = false;
    }
}

.section-panel {
    max-width: 640px;
}

.section-title {
    margin-bottom: 1.5rem;
    font-weight: 600;
    color: #333;
}

.toast-message {
    padding: 0.75rem 1rem;
    border-radius: 6px;
    margin-bottom: 1rem;
    font-size: 0.9rem;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.appearance-form {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

.option-group {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 1rem;
}

.option-group legend {
    font-weight: 600;
    font-size: 0.9rem;
    color: #444;
    padding: 0 0.25rem;
    width: auto;
}

.radio-options {
    display: flex;
    gap: 0.75rem;
    margin-top: 0.5rem;
}

.radio-option {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.5rem 1rem;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.15s;
}

.radio-option:hover {
    background: #f8f9fa;
}

.radio-option.selected {
    background: #e7f1ff;
    border-color: #0d6efd;
    color: #0d6efd;
}

.radio-option input[type="radio"] {
    accent-color: #0d6efd;
}

.form-group {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
}

.form-group label {
    font-weight: 600;
    font-size: 0.9rem;
    color: #444;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.85rem 1rem;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    cursor: pointer;
}

.toggle-row:hover {
    background: #f8f9fa;
}

/* Live Preview */
.preview-area {
    border: 2px dashed #dee2e6;
    border-radius: 8px;
    padding: 1.5rem;
    transition: all 0.3s;
}

.preview-title {
    margin-bottom: 0.5rem;
    font-weight: 600;
}

.preview-text {
    margin-bottom: 1rem;
}

.preview-card {
    background: rgba(0, 0, 0, 0.03);
    border: 1px solid rgba(0, 0, 0, 0.08);
    border-radius: 6px;
    padding: 1rem;
}

.preview-card p {
    margin: 0.5rem 0;
}

.preview-btn {
    padding: 0.35rem 0.75rem;
    border-radius: 4px;
    border: 1px solid #0d6efd;
    background: #0d6efd;
    color: #fff;
    cursor: default;
    font-size: inherit;
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #333;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .preview-card {
    background: rgba(255, 255, 255, 0.06);
    border-color: rgba(255, 255, 255, 0.1);
}

.preview-system {
    background: #f0f0f0;
    color: #333;
}

/* Font size variants */
